const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
return { json: { token } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
if (row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'admin role required' } };
return { json: { _ok: true } };

const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const spendRows  = allOf('Fetch MTD Spend');
const budgets    = allOf('Fetch Budgets');
const alerts     = allOf('Fetch Alerts');
const breakers   = allOf('Fetch Breakers');

const today = new Date().toISOString().slice(0,10);
const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0,10);
const monthStart = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().slice(0,10);
const daysInMonth = new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).getDate();
const dayOfMonth = new Date().getDate();

// Aggregate by service
const mtdByService = {};
const todayByService = {};
const yesterdayByService = {};
let mtdTotal = 0;
spendRows.forEach(function (r) {
  const s = r.service_name;
  const c = parseInt(r.spend_cents) || 0;
  mtdByService[s] = (mtdByService[s] || 0) + c;
  mtdTotal += c;
  if (r.tracking_date === today)     todayByService[s] = (todayByService[s] || 0) + c;
  if (r.tracking_date === yesterday) yesterdayByService[s] = (yesterdayByService[s] || 0) + c;
});

// Project month-end: MTD / daysElapsed × daysInMonth
const projectedByService = {};
const daysElapsed = Math.max(1, dayOfMonth);
Object.keys(mtdByService).forEach(function (s) {
  projectedByService[s] = Math.round((mtdByService[s] / daysElapsed) * daysInMonth);
});

// Budgets with computed pct used + status
const enrichedBudgets = budgets.map(function (b) {
  const spent = (b.service_name === 'total_platform') ? mtdTotal : (mtdByService[b.service_name] || 0);
  const pct   = b.monthly_limit_cents > 0 ? (spent * 100 / b.monthly_limit_cents) : 0;
  let status = 'ok';
  if (pct >= (b.auto_pause_pct || 90)) status = 'emergency';
  else if (pct >= (b.critical_pct || 75)) status = 'critical';
  else if (pct >= (b.warning_pct  || 50)) status = 'warning';
  return Object.assign({}, b, { mtd_spend_cents: spent, percent_used: Math.round(pct * 10) / 10, status });
});

return { json: { ok: true, generated_at: new Date().toISOString(), period: { month_start: monthStart, days_in_month: daysInMonth, day_of_month: dayOfMonth, days_elapsed: daysElapsed }, totals: { mtd_cents: mtdTotal, projected_month_end_cents: Math.round((mtdTotal / daysElapsed) * daysInMonth) }, by_service: { mtd: mtdByService, today: todayByService, yesterday: yesterdayByService, projected_month_end: projectedByService }, budgets: enrichedBudgets, alerts: alerts, breakers: breakers } };
